function wpbp_count_block_types($html) {
    $processor = new WP_Block_Processor();
    $processor->set_content($html);
    $counts = [];

    $processor->parse_blocks(function ($block) use (&$counts) {
        $block_name = $block['blockName'] ?? '';
        if (empty($block_name) || $block_name === 'core/freeform') {
            return;
        }

        if (isset($counts[$block_name])) {
            $counts[$block_name]++;
        } else {
            $counts[$block_name] = 1;
        }

        if (isset($block['innerBlocks'])) {
            foreach ($block['innerBlocks'] as $inner_block) {
                $inner_block_name = $inner_block['blockName'] ?? '';
                if (empty($inner_block_name) || $inner_block_name === 'core/freeform') {
                    continue;
                }

                if (isset($counts[$inner_block_name])) {
                    $counts[$inner_block_name]++;
                } else {
                    $counts[$inner_block_name] = 1;
                }
            }
        }
    });

    return $counts;
}

