add_action('wp_abilities_api_init', function () {
    register_abilities_api_ability('demo/get-movies', [
        'input' => [
            'type' => 'object',
            'properties' => [
                'genre' => ['type' => 'string', 'description' => 'Filter movies by genre']
            ],
            'required' => []
        ],
        'output' => ['type' => 'array', 'items' => ['type' => 'string']],
        'permission_callback' => function () {
            return is_user_logged_in();
        },
        'meta' => [
            'show_in_rest' => true
        ],
        'callback' => function ($args) {
            $genre = $args['genre'] ?? null;
            $salt = wp_cache_get_last_changed('post');
            $cache_key = 'demo_get_movies_' . ($genre ? md5($genre) : 'all');
            $cache_key = wp_cache_get_salted($cache_key, 'post-queries', $salt);

            $movies = wp_cache_get($cache_key, 'post-queries');

            if ($movies === false) {
                $query_args = ['post_type' => 'movie', 'posts_per_page' => -1];
                if ($genre) {
                    $query_args['tax_query'] = [
                        [
                            'taxonomy' => 'movie_genre',
                            'field' => 'slug',
                            'terms' => $genre
                        ]
                    ];
                }
                $query = new WP_Query($query_args);
                $movies = wp_list_pluck($query->posts, 'post_title');
                wp_cache_set($cache_key, $movies, 'post-queries', 3600);
            }

            return $movies;
        }
    ]);
});

