function wpbp_get_options_cached(array $keys) {
    $group = 'options';
    $cache = wp_cache_get_multiple($keys, $group, false, $misses);
    $misses = array_diff($keys, array_keys($cache));
    $result = [];

    foreach ($cache as $key => $value) {
        if ($value !== false) {
            $result[$key] = $value;
        }
    }

    foreach ($misses as $key) {
        $value = get_option($key);
        if ($value !== false) {
            $result[$key] = $value;
            wp_cache_set($key, $value, $group);
        }
    }

    return $result;
}

