function wpbp_strip_scripts($html) {
    $processor = new WP_HTML_Tag_Processor($html);
    $output = '';

    while ($processor->next_tag('script')) {
        $output .= $processor->get_before();
        $processor->skip_tag();
    }

    $output .= $processor->get_remaining();

    return $output;
}

