function wpbp_replace_script_text($html, $replacement) {
    $processor = new WP_HTML_Tag_Processor($html);
    if (!$processor->next_tag('script')) {
        return $html;
    }
    if (strpos($replacement, '<script') !== false || strpos($replacement, '</script') !== false) {
        return false;
    }
    if (!$processor->set_modifiable_text($replacement)) {
        return false;
    }
    return $processor->get_updated_html();
}

