function wpbp_router_link($url, $text) {
    $escaped_url = esc_url($url);
    $escaped_text = esc_html($text);
    $home_url = home_url();
    $is_external = parse_url($url, PHP_URL_SCHEME) !== parse_url($home_url, PHP_URL_SCHEME) || parse_url($url, PHP_URL_HOST) !== parse_url($home_url, PHP_URL_HOST);
    $rel_attr = $is_external ? ' rel="nofollow"' : '';
    return '<a href="' . $escaped_url . '" data-wp-router-replace="true" data-wp-router-prefetch="intent"' . $rel_attr . '>' . $escaped_text . '</a>';
}

