function get_books_endpoint() {
    $cache_key = 'books-list';
    $cache_group = 'books-list';
    $last_changed = wp_cache_get_last_changed('posts');
    $cache_salt = $last_changed;

    $books = wp_cache_get_salted($cache_key, $cache_group, $cache_salt);

    if (false === $books) {
        $args = array(
            'post_type' => 'book',
            'post_status' => 'publish',
            'posts_per_page' => -1,
        );

        $query = new WP_Query($args);
        $books = array_map(function ($post) {
            return $post->post_title;
        }, $query->posts);

        wp_cache_set_salted($cache_key, $books, $cache_group, $cache_salt);
    }

    return new WP_REST_Response($books, 200);
}

